checker_dsl:
EXISTS (`R`) {
  AND {
    (`the root term of R has a parent that is a RegExpLiteral`),
    (`the root term of R is used as a regular expression`),
    NOT { (`R has a child that is a RegExpEscape`) },
    NOT { (`R is a child of a RegExpCharacterClass where the first child is a RegExpNormalChar with value "["`) },
    EXISTS (`Priority0, Message0`) {
      AND {
        (`Priority0 = 0`),
        (`R is an OverlyWideRange`),
        EXISTS (`Low, High, NumChars`) {
          AND {
            (`R has a character range from integer code point Low to High`),
            (`NumChars = 1 + High - Low`),
            (`NumChars >= 10`),
            OR {
              AND {
                (`the code point of character 'Z' >= Low`),
                (`the code point of character 'a' <= High`)
              },
              AND {
                (`the code point of character '9' >= Low`),
                (`the code point of character 'A' <= High`)
              },
              AND {
                EXISTS (`Bound`) {
                  AND {
                    (`Bound is either Low or High`),
                    NOT { (`the character with code point Bound is alphanumeric`) }
                  }
                },
                (`Low < 128`),
                (`High < 128`)
              }
            },
            NOT {
              (`R has a character range where: high bound is "~", or low bound is either " " or "!", or low bound is "@" and high bound is "_", or low bound is null character (code point 0), or low bound is "0" and high bound is "?", or low bound is "@" and high bound is "Z"`)
            }
          }
        },
        EXISTS (`Equiv`) {
          (`Equiv is the printEquivalent string representation of R as an OverlyWideRange`)
        }
      }
    },
    EXISTS (`Priority1, Message1`) {
      AND {
        (`Priority1 = 1`),
        EXISTS (`Other`) {
          AND {
            (`the rankRange of R is less than the rankRange of Other`),
            (`R and Other are both children of the same RegExpCharacterClass`),
            (`R != Other`),
            EXISTS (`ALow, AHigh, BLow, BHigh`) {
              AND {
                (`R has a character range from integer code point ALow to AHigh`),
                (`Other has a character range from integer code point BLow to BHigh`),
                (`ALow <= BHigh`),
                (`BLow <= AHigh`)
              }
            }
          }
        }
      }
    },
    EXISTS (`Priority2, Message2`) {
      AND {
        (`Priority2 = 2`),
        EXISTS (`Escape`) {
          AND {
            (`R and Escape are both children of the same RegExpCharacterClass`),
            OR {
              AND {
                (`Escape has value "w"`),
                EXISTS (`Low, High`) {
                  AND {
                    (`R has a character range from character Low to High`),
                    (`the set of characters from code point of Low to code point of High matches the regex pattern \w`)
                  }
                }
              },
              AND {
                (`Escape has value "d"`),
                EXISTS (`Low, High`) {
                  AND {
                    (`R has a character range from character Low to High`),
                    (`the set of characters from code point of Low to code point of High matches the regex pattern \d`)
                  }
                }
              },
              AND {
                (`Escape has value "s"`),
                EXISTS (`Low, High`) {
                  AND {
                    (`R has a character range from character Low to High`),
                    (`the set of characters from code point of Low to code point of High matches the regex pattern \s`)
                  }
                }
              }
            }
          }
        }
      }
    },
    EXISTS (`Priority3, Message3`) {
      AND {
        (`Priority3 = 3`),
        EXISTS (`Low, High`) {
          AND {
            (`R has a character range from integer code point Low to High`),
            (`Low > High`)
          }
        }
      }
    }
  }
}
